import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.filter.OncePerRequestFilter;

public class JWTVerificationFilter extends OncePerRequestFilter {
    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain) throws ServletException, IOException {
        String authHeader = request.getHeader("Authorization");
        if (authHeader != null && authHeader.startsWith("Bearer ")) {
            String token = authHeader.substring(7); // remove the 'Bearer ' prefix

            try {
                JWTParser parser = new DefaultJWTParser();
                JWSObject jwsObject = parser.parse(token);
                JWTClaimsSet claimsSet = jwsObject.getPayload().toJSONObject();

                String userId = (String) claimsSet.getClaim("userId");
                UsernamePasswordAuthenticationToken authToken = new UsernamePasswordAuthenticationToken(userId, null, Collections.emptyList());
                SecurityContextHolder.getContext().setAuthentication(authToken);
            } catch (ParseException | JOSEException e) {
                // handle exception
            }
        }

        filterChain.doFilter(request, response);
    }
}